#ifndef OSK_MEMLAYOUT_H
#define OSK_MEMLAYOUT_H

/*
 * Current RISC-V memory layout.
 *
 * This file describes the layout used by the current minimal kernel, not the
 * final layout we want. Paging is not enabled yet, so every address below is
 * effectively both a virtual address and a physical address.
 *
 * The teaching OS in ../23241036 has a better long-term model:
 *   - user space lives below ULIM/KSEG0, for example UTEXT = 0x00400000;
 *   - kernel space lives at and above 0x80000000;
 *   - PADDR/KADDR translate between kernel virtual addresses and physical
 *     addresses;
 *   - user addresses are backed by page tables/TLB mappings, so a user program
 *     can use low virtual addresses even if the real RAM is elsewhere.
 *
 * With Sv39 enabled, user programs now use low virtual addresses. The kernel
 * keeps a direct mapping for physical RAM so it can still access allocated
 * pages by physical address while building page tables.
 *
 * Current temporary map:
 *   0x10000000..0x10000fff  UART0 MMIO on QEMU virt.
 *   0x00010000..            user ELF text/data load area.
 *   elf_loaded_end()..      user brk heap.
 *   0x02000000              current user brk heap upper limit.
 *   0x100000000..0x110000000 simple mmap area, allocated upward.
 *   0x3efff00000..0x3f00000000  initial user stack.
 *   0x10000000..0x10000fff  UART0 MMIO on QEMU virt.

