static void trim(char *s)
{
    unsigned long i = 0;
    unsigned long len;

    while (s[i] == ' ' || s[i] == '\t' || s[i] == '\r') {
        i++;
    }
    if (i > 0) {
        unsigned long j = 0;
        while (s[i] != '\0') {
            s[j++] = s[i++];
        }
        s[j] = '\0';
    }

    len = strlen(s);
    while (len > 0 &&
           (s[len - 1] == ' ' || s[len - 1] == '\t' || s[len - 1] == '\r')) {
        s[--len] = '\0';
    }
}

static void strip_quotes(char *s)
{
    unsigned long len = strlen(s);

    if (len >= 2 &&
        ((s[0] == '"' && s[len - 1] == '"') ||
         (s[0] == '\'' && s[len - 1] == '\''))) {
        unsigned long i;

        for (i = 1; i < len - 1; i++) {
            s[i - 1] = s[i];
        }
        s[len - 2] = '\0';
    }
}

static int split_words(char *line, char *argv[], int max_argc)
{
    int argc = 0;
    char quote = 0;
    char *p = line;

    while (*p != '\0' && argc < max_argc - 1) {
        while (*p == ' ' || *p == '\t') {
            *p++ = '\0';
        }
        if (*p == '\0') {
            break;
        }
        argv[argc++] = p;
        while (*p != '\0') {
            if (quote != 0) {
                if (*p == quote) {
                    quote = 0;
                }
            } else if (*p == '\'' || *p == '"') {
                quote = *p;
            } else if (*p == ' ' || *p == '\t') {
                break;
            }
            p++;
        }
    }
    argv[argc] = 0;
    return argc;
}

static int is_env_assignment(const char *s)
{
    unsigned long i;

    if (s == 0 || s[0] == '\0' || s[0] == '=') {
        return 0;
    }
    for (i = 0; s[i] != '\0'; i++) {
        if (s[i] == '=') {
