static int elf_is_valid(const struct Elf64_Ehdr *ehdr, usize size)
{
    if (size < sizeof(*ehdr)) {
        return 0;
    }

    return ehdr->e_ident[EI_MAG0] == ELFMAG0 &&
           ehdr->e_ident[EI_MAG1] == ELFMAG1 &&
           ehdr->e_ident[EI_MAG2] == ELFMAG2 &&
           ehdr->e_ident[EI_MAG3] == ELFMAG3 &&
           ehdr->e_ident[EI_CLASS] == ELFCLASS64 &&
           ehdr->e_ident[EI_DATA] == ELFDATA2LSB &&
           (ehdr->e_type == ET_EXEC || ehdr->e_type == ET_DYN) &&
           ehdr->e_machine == EM_RISCV;
}

int elf_get_interp(const void *image, usize size, char *buf, usize buf_size)
{
    const struct Elf64_Ehdr *ehdr = (const struct Elf64_Ehdr *)image;
    const u8 *base = (const u8 *)image;
    u16 i;

    if (buf == NULL || buf_size == 0) {
        return -EINVAL;
    }
    buf[0] = '\0';

    if (!elf_is_valid(ehdr, size)) {
        return -EINVAL;
    }
    if (ehdr->e_phoff + (usize)ehdr->e_phentsize * ehdr->e_phnum > size) {
        return -EINVAL;
    }

    for (i = 0; i < ehdr->e_phnum; i++) {
        const struct Elf64_Phdr *ph =
            (const struct Elf64_Phdr *)(base + ehdr->e_phoff + (usize)i * ehdr->e_phentsize);

        if (ph->p_type != PT_INTERP) {
            continue;
        }
        if (ph->p_offset + ph->p_filesz > size || ph->p_filesz >= buf_size) {
            return -EINVAL;
        }
        memcpy(buf, base + ph->p_offset, ph->p_filesz);
        buf[ph->p_filesz] = '\0';
        return 1;
    }

    return 0;
}

int elf_interp_is_optional(const void *image, usize size)
{
    const struct Elf64_Ehdr *ehdr = (const struct Elf64_Ehdr *)image;
    const u8 *base = (const u8 *)image;
    const struct Elf64_Phdr *dynamic = NULL;
    u16 i;

    if (!elf_is_valid(ehdr, size)) {
        return 0;
    }
    if (ehdr->e_phoff + (usize)ehdr->e_phentsize * ehdr->e_phnum > size) {
        return 0;
    }

    for (i = 0; i < ehdr->e_phnum; i++) {
        const struct Elf64_Phdr *ph =
            (const struct Elf64_Phdr *)(base + ehdr->e_phoff + (usize)i * ehdr->e_phentsize);

        if (ph->p_type == PT_DYNAMIC) {
            dynamic = ph;
            break;
        }
    }
    if (dynamic == NULL) {
        return 1;
    }
    if (dynamic->p_offset + dynamic->p_filesz > size ||
        dynamic->p_filesz < sizeof(struct Elf64_Dyn)) {
        return 0;
    }

    for (i = 0; (usize)(i + 1) * sizeof(struct Elf64_Dyn) <= dynamic->p_filesz; i++) {
        const struct Elf64_Dyn *dyn =
            (const struct Elf64_Dyn *)(base + dynamic->p_offset +
                                       (usize)i * sizeof(struct Elf64_Dyn));

        if (dyn->d_tag == DT_NULL) {
            return 1;
        }
        if (dyn->d_tag == DT_NEEDED) {
            return 0;
        }
        if ((dyn->d_tag == DT_RELASZ || dyn->d_tag == DT_RELSZ ||
             dyn->d_tag == DT_PLTRELSZ) && dyn->d_un.d_val != 0) {
            return 0;
        }
    }
    return 0;
}

int elf_load_into_at(pagetable_t root, const void *image, usize size,
                     uintptr_t requested_bias, struct ElfLoadInfo *info)
{
    const struct Elf64_Ehdr *ehdr = (const struct Elf64_Ehdr *)image;
    const u8 *base = (const u8 *)image;
    u16 i;
    uintptr_t end = 0;
    uintptr_t load_bias;

    if (!elf_is_valid(ehdr, size)) {
        return -EINVAL;
    }

    if (ehdr->e_phoff + (usize)ehdr->e_phentsize * ehdr->e_phnum > size) {
        return -EINVAL;
    }

    load_bias = ehdr->e_type == ET_DYN ? requested_bias : 0;
    if (info != NULL) {
        memset(info, 0, sizeof(*info));
        info->bias = load_bias;
        info->entry = (uintptr_t)ehdr->e_entry + load_bias;
        info->phent = ehdr->e_phentsize;
        info->phnum = ehdr->e_phnum;
        info->phdr = 0;
    }

    for (i = 0; i < ehdr->e_phnum; i++) {
        const struct Elf64_Phdr *ph =
            (const struct Elf64_Phdr *)(base + ehdr->e_phoff + (usize)i * ehdr->e_phentsize);
        uintptr_t seg_start = (uintptr_t)ph->p_vaddr + load_bias;
        uintptr_t seg_end;
        uintptr_t page_va;
        u64 perm = PTE_U | PTE_R;

        if (ph->p_type != PT_LOAD) {
            if (ph->p_type == PT_PHDR && info != NULL) {
                info->phdr = (uintptr_t)ph->p_vaddr + load_bias;
            } else if (ph->p_type == PT_DYNAMIC && info != NULL) {
                info->dynamic = (uintptr_t)ph->p_vaddr + load_bias;
            }
            continue;
        }

        if (info != NULL && info->phdr == 0 &&
            ehdr->e_phoff >= ph->p_offset &&
            ehdr->e_phoff + (usize)ehdr->e_phentsize * ehdr->e_phnum <=
                ph->p_offset + ph->p_filesz) {
            info->phdr = (uintptr_t)ph->p_vaddr + load_bias +
                         (uintptr_t)(ehdr->e_phoff - ph->p_offset);
        }

        if (ph->p_offset + ph->p_filesz > size || ph->p_filesz > ph->p_memsz) {
            return -EINVAL;
        }

        if (ph->p_flags & PF_W) {
            perm |= PTE_W;
        }
        if (ph->p_flags & PF_X) {
            perm |= PTE_X;
        }

        seg_end = seg_start + ph->p_memsz;
        for (page_va = align_down(seg_start, 4096);
             page_va < align_up(seg_end, 4096);
             page_va += 4096) {
            void *page = vm_alloc_page();
            int ret = vm_map(root, page_va, (uintptr_t)page, 4096, perm);
            usize copy_start;
            usize copy_end;

            if (ret < 0) {
                vm_free_page(page);
                return ret;
            }

            copy_start = page_va < seg_start ? seg_start - page_va : 0;
            if (page_va >= seg_start + ph->p_filesz) {
                copy_end = 0;
            } else {
                copy_end = page_va + 4096 > seg_start + ph->p_filesz
                    ? seg_start + ph->p_filesz - page_va
                    : 4096;
            }

            if (copy_start < copy_end) {
                memcpy((u8 *)page + copy_start,
                       base + ph->p_offset + (page_va + copy_start - seg_start),
                       copy_end - copy_start);
            }
        }

        if (seg_end > end) {
            end = seg_end;
        }
    }

    sfence_vma();
    loaded_end = align_up(end, 4096);
    if (info != NULL) {
        if (info->phdr == 0) {
            info->phdr = load_bias + (uintptr_t)ehdr->e_phoff;
        }
        info->loaded_end = loaded_end;
    }
    return 0;
}

int elf_load_into(pagetable_t root, const void *image, usize size, void (**entry)(void))
{
    struct ElfLoadInfo info;
    int ret = elf_load_into_at(root, image, size, USER_BASE, &info);

    if (ret < 0) {
        return ret;
    }
    if (entry != NULL) {
        *entry = (void (*)(void))info.entry;
    }
    return 0;
}

int elf_load(const void *image, usize size, void (**entry)(void))
{
    return elf_load_into(vm_kernel_pagetable(), image, size, entry);
}

uintptr_t elf_loaded_end(void)
{
    return loaded_end;
}

