    block_init();
    ext4_init();
    if (!ext4_available() || ext4_lookup_path("/", &root) < 0) {
        puts("init: no readable ext4 test disk\n");
        return;
    }

    scan_inode_and_skip(root, 0, &found, seen, &seen_count);
    if (!found) {
        puts("init: no test scripts found\n");
    }
}

